<?phpdeclare(strict_types=1);/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}/***BackupManagementPage*Managedatabasebackupsandrestore*/session_start();require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/auth_helper.php';/Checkauthenticationif(!AuthHelper::validateSession()){header('Location:'.url('login.php'));exit;}$pageTitle='ManajemenBackup';include__DIR__.'/../includes/components/header.php';?><divclass="container-fluidpy-4"><!--PageHeader--><divclass="d-flexjustify-content-betweenalign-items-centermb-4"><div><h2class="mb-1"><iclass="fasfa-databasetext-primaryme-2"></i>ManajemenBackup</h2><pclass="text-mutedmb-0">Backupdanrestoredatabasesistem</p></div><divclass="d-flexgap-2"><buttonclass="btnbtn-success"onclick="createBackup()"><iclass="fasfa-plusme-2"></i>BuatBackup</button><buttonclass="btnbtn-outline-primary"onclick="runScheduledBackups()"><iclass="fasfa-clockme-2"></i>RunScheduled</button></div></div><!--StatsCards--><divclass="rowmb-4"><divclass="col-md-3"><divclass="cardbg-primarytext-white"><divclass="card-body"><divclass="d-flexjustify-content-between"><div><h6class="mb-0">TotalBackup</h6><h3class="mb-0"id="totalBackups">-</h3></div><divclass="align-self-center"><iclass="fasfa-archivefa-2xopacity-50"></i></div></div></div></div></div><divclass="col-md-3"><divclass="cardbg-successtext-white"><divclass="card-body"><divclass="d-flexjustify-content-between"><div><h6class="mb-0">BackupBerhasil</h6><h3class="mb-0"id="completedBackups">-</h3></div><divclass="align-self-center"><iclass="fasfa-check-circlefa-2xopacity-50"></i></div></div></div></div></div><divclass="col-md-3"><divclass="cardbg-warningtext-white"><divclass="card-body"><divclass="d-flexjustify-content-between"><div><h6class="mb-0">TotalSize</h6><h3class="mb-0"id="totalSize">-</h3></div><divclass="align-self-center"><iclass="fasfa-hddfa-2xopacity-50"></i></div></div></div></div></div><divclass="col-md-3"><divclass="cardbg-infotext-white"><divclass="card-body"><divclass="d-flexjustify-content-between"><div><h6class="mb-0">BackupTerakhir</h6><h5class="mb-0"id="latestBackup">-</h5></div><divclass="align-self-center"><iclass="fasfa-clockfa-2xopacity-50"></i></div></div></div></div></div></div><!--BackupsTable--><divclass="cardshadow-sm"><divclass="card-headerbg-whitepy-3"><divclass="d-flexjustify-content-betweenalign-items-center"><h5class="mb-0"><iclass="fasfa-listme-2"></i>DaftarBackup</h5><divclass="d-flexgap-2"><selectclass="form-select"id="filterStatus"style="width:150px;"><optionvalue="">SemuaStatus</option><optionvalue="completed">Berhasil</option><optionvalue="failed">Gagal</option><optionvalue="running">Running</option></select><buttonclass="btnbtn-outline-secondary"onclick="loadBackups()"><iclass="fasfa-sync-alt"></i></button></div></div></div><divclass="card-bodyp-0"><divclass="table-responsive"><tableclass="tabletable-hovermb-0"id="backupsTable"><theadclass="table-light"><tr><th>ID</th><th>Filename</th><th>Type</th><th>Size</th><th>Status</th><th>Dibuat</th><th>Oleh</th><th>Aksi</th></tr></thead><tbodyid="backupsTableBody"><tr><tdcolspan="8"class="text-centerpy-4"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div><pclass="mt-2text-muted">Memuatdatabackup...</p></td></tr></tbody></table></div></div></div></div><!--CreateBackupModal--><divclass="modalfade"id="createBackupModal"tabindex="-1"data-bs-backdrop="static"data-bs-keyboard="false"><divclass="modal-dialogmodal-md"data-bs-backdrop="static"data-bs-keyboard="false"><divclass="modal-content"data-bs-backdrop="static"data-bs-keyboard="false"><divclass="modal-header"data-bs-backdrop="static"data-bs-keyboard="false"><h5class="modal-title"><iclass="fasfa-databaseme-2"></i>BuatBackupBaru</h5><buttontype="button"class="btn-close"data-bs-dismiss="modal"></button></div><divclass="modal-body"data-bs-backdrop="static"data-bs-keyboard="false"><formid="createBackupForm"><divclass="mb-3"><labelclass="form-label">TipeBackup</label><selectclass="form-select"name="type"><optionvalue="full">FullBackup(SemuaTabel)</option><optionvalue="partial">PartialBackup(TabelTertentu)</option></select></div><divclass="mb-3"id="tablesField"style="display:none;"><labelclass="form-label">Tabelyangdi-backup(pisahkandengankoma)</label><inputtype="text"class="form-control"name="tables"placeholder="personil,bagian,jabatan"></div></form></div><divclass="modal-footer"data-bs-backdrop="static"data-bs-keyboard="false"><buttontype="button"class="btnbtn-secondary"data-bs-dismiss="modal">Batal</button><buttontype="button"class="btnbtn-primary"onclick="confirmCreateBackup()"><iclass="fasfa-playme-2"></i>MulaiBackup</button></div></div></div></div><script>/Loadbackupsonpageloaddocument.addEventListener('DOMContentLoaded',function(){loadBackups();loadStats();/Show/hidetablesfieldbasedontypedocument.querySelector('[name="type"]').addEventListener('change',function(){document.getElementById('tablesField').style.display=this.value==='partial'?'block':'none';});});/LoadbackupsfromAPIasyncfunctionloadBackups(){try{constresponse=awaitfetch(api_url('backup_api.php?action=list'));constdata=awaitresponse.json();if(data.success){renderBackupsTable(data.data.backups);}else{showAlert('danger',data.message);}}catch(error){console.error('Errorloadingbackups:',error);showAlert('danger','Gagalmemuatdatabackup');}}/LoadstatisticsasyncfunctionloadStats(){try{constresponse=awaitfetch(api_url('backup_api.php?action=stats'));constdata=awaitresponse.json();if(data.success){conststats=data.data.stats;document.getElementById('totalBackups').textContent=stats.total;document.getElementById('completedBackups').textContent=stats.completed;/Formatsizeconstsize=formatBytes(stats.total_size);document.getElementById('totalSize').textContent=size;/Latestbackupif(data.data.latest_backup){constdate=newDate(data.data.latest_backup.created_at);document.getElementById('latestBackup').textContent=date.toLocaleDateString('id-ID');}else{document.getElementById('latestBackup').textContent='Belumada';}}}catch(error){console.error('Errorloadingstats:',error);}}/RenderbackupstablefunctionrenderBackupsTable(backups){consttbody=document.getElementById('backupsTableBody');constfilterStatus=document.getElementById('filterStatus').value;/Filterbystatusif(filterStatus){backups=backups.filter(b=>b.status===filterStatus);}if(backups.length===0){tbody.innerHTML=`<tr><tdcolspan="8"class="text-centerpy-4text-muted"><iclass="fasfa-inboxfa-3xmb-3opacity-25"></i><p>Belumadabackupyangdibuat</p></td></tr>`;return;}tbody.innerHTML=backups.map(backup=>`<tr><td>${backup.id}</td><td><iclass="fasfa-file-codetext-primaryme-2"></i>${escapeHtml(backup.filename)}</td><td><spanclass="badgebg-${backup.backup_type==='full'?'primary':'info'}">${backup.backup_type==='full'?'Full':'Partial'}</span>${backup.is_auto?'<spanclass="badgebg-secondaryms-1">Auto</span>':''}</td><td>${backup.file_size_formatted}</td><td><spanclass="badgebg-${getStatusColor(backup.status)}">${getStatusLabel(backup.status)}</span></td><td>${formatDate(backup.created_at)}</td><td>${backup.created_by_name||'System'}</td><td>${backup.status==='completed'?`<buttonclass="btnbtn-smbtn-success"onclick="downloadBackup(${backup.id})"title="Download"><iclass="fasfa-download"></i></button><buttonclass="btnbtn-smbtn-warning"onclick="restoreBackup(${backup.id})"title="Restore"><iclass="fasfa-undo"></i></button>`:''}<buttonclass="btnbtn-smbtn-danger"onclick="deleteBackup(${backup.id})"title="Hapus"><iclass="fasfa-trash"></i></button></td></tr>`).join('');}/CreatebackupfunctioncreateBackup(){document.getElementById('createBackupForm').reset();constmodal=newbootstrap.Modal(document.getElementById('createBackupModal'));modal.show();}asyncfunctionconfirmCreateBackup(){constform=document.getElementById('createBackupForm');constformData=newFormData(form);formData.append('action','create');/Closemodalbootstrap.Modal.getInstance(document.getElementById('createBackupModal')).hide();/ShowloadingshowAlert('info','Sedangmembuatbackup,mohontunggu...');try{constresponse=awaitfetch(api_url('backup_api.php'),{method:'POST',body:formData});constdata=awaitresponse.json();if(data.success){showAlert('success',`Backupberhasildibuat:${data.data.filename}(${data.data.file_size})`);loadBackups();loadStats();}else{showAlert('danger',data.message);}}catch(error){console.error('Errorcreatingbackup:',error);showAlert('danger','Gagalmembuatbackup');}}/DownloadbackupfunctiondownloadBackup(backupId){window.open(`api/backup_api.php?action=download&backup_id=${backupId}`,'_blank');}/RestorebackupasyncfunctionrestoreBackup(backupId){if(!confirm('⚠️PERINGATAN:Restoreakanmenggantiseluruhdatasaatinidengandatadaribackup.\n\nApakahAndayakininginmelanjutkan?')){return;}constformData=newFormData();formData.append('action','restore');formData.append('backup_id',backupId);showAlert('info','Sedangmelakukanrestore,mohontunggu...');try{constresponse=awaitfetch(api_url('backup_api.php'),{method:'POST',body:formData});constdata=awaitresponse.json();if(data.success){showAlert('success',data.message);}else{showAlert('danger',data.message);}}catch(error){console.error('Errorrestoringbackup:',error);showAlert('danger','Gagalmelakukanrestore');}}/DeletebackupasyncfunctiondeleteBackup(backupId){if(!confirm('ApakahAndayakininginmenghapusbackupini?')){return;}constformData=newFormData();formData.append('action','delete');formData.append('backup_id',backupId);try{constresponse=awaitfetch(api_url('backup_api.php'),{method:'POST',body:formData});constdata=awaitresponse.json();if(data.success){showAlert('success',data.message);loadBackups();loadStats();}else{showAlert('danger',data.message);}}catch(error){console.error('Errordeletingbackup:',error);showAlert('danger','Gagalmenghapusbackup');}}/RunscheduledbackupsasyncfunctionrunScheduledBackups(){if(!confirm('Jalankansemuascheduledbackupyangsudahjatuhtempo?')){return;}showAlert('info','Menjalankanscheduledbackups...');try{constresponse=awaitfetch(api_url('backup_api.php'),{method:'POST',body:newURLSearchParams({action:'run_scheduled'})});constdata=awaitresponse.json();if(data.success){constresults=data.data.results;constsuccess=results.filter(r=>r.success).length;showAlert('success',`${success}dari${results.length}scheduledbackupberhasildijalankan`);loadBackups();loadStats();}else{showAlert('danger',data.message);}}catch(error){console.error('Errorrunningscheduled:',error);showAlert('danger','Gagalmenjalankanscheduledbackups');}}/HelperfunctionsfunctiongetStatusColor(status){constcolors={'completed':'success','failed':'danger','running':'warning','pending':'secondary'};returncolors[status]||'secondary';}functiongetStatusLabel(status){constlabels={'completed':'Berhasil','failed':'Gagal','running':'Running','pending':'Pending'};returnlabels[status]||status;}functionescapeHtml(text){if(!text)return'';constdiv=document.createElement('div');div.textContent=text;returndiv.innerHTML;}functionformatDate(dateString){constdate=newDate(dateString);returndate.toLocaleString('id-ID');}functionformatBytes(bytes){if(!bytes)return'0B';constunits=['B','KB','MB','GB'];letunitIndex=0;while(bytes>=1024&&unitIndex<units.length-1){bytes/=1024;unitIndex++;}returnMath.round(bytes*100)/100+''+units[unitIndex];}functionshowAlert(type,message){alert(message);}</script><?phpinclude__DIR__.'/../includes/components/footer.php';?>
